// mm/src/utils/fileStore.js
// Stores File blobs in IndexedDB so we can recover after navigating to Register/Login.

const DB_NAME = 'mm_files_db';
const STORE = 'workflow_files';
const DB_VERSION = 1;

function openDb() {
  return new Promise((resolve, reject) => {
    const req = indexedDB.open(DB_NAME, DB_VERSION);

    req.onupgradeneeded = () => {
      const db = req.result;
      if (!db.objectStoreNames.contains(STORE)) {
        db.createObjectStore(STORE, { keyPath: 'id' });
      }
    };

    req.onsuccess = () => resolve(req.result);
    req.onerror = () => reject(req.error);
  });
}

function txDone(tx) {
  return new Promise((resolve, reject) => {
    tx.oncomplete = () => resolve();
    tx.onerror = () => reject(tx.error);
    tx.onabort = () => reject(tx.error);
  });
}

export async function saveWorkflowFile({ id, file, name, size, tag }) {
  if (!id || !file) throw new Error('saveWorkflowFile requires {id, file}');

  const db = await openDb();
  const tx = db.transaction(STORE, 'readwrite');
  const store = tx.objectStore(STORE);

  store.put({
    id,
    file, // File/Blob stored here
    name: name || file.name || '',
    size: size ?? file.size ?? 0,
    tag: tag || 'Main Manuscript',
    savedAt: new Date().toISOString(),
  });

  await txDone(tx);
  db.close();
}

export async function loadWorkflowFiles() {
  const db = await openDb();
  const tx = db.transaction(STORE, 'readonly');
  const store = tx.objectStore(STORE);

  const req = store.getAll();

  const rows = await new Promise((resolve, reject) => {
    req.onsuccess = () => resolve(req.result || []);
    req.onerror = () => reject(req.error);
  });

  await txDone(tx);
  db.close();

  return rows; // [{id, file, name, size, tag, savedAt}]
}

export async function deleteWorkflowFile(id) {
  const db = await openDb();
  const tx = db.transaction(STORE, 'readwrite');
  tx.objectStore(STORE).delete(id);
  await txDone(tx);
  db.close();
}

export async function clearWorkflowFiles() {
  const db = await openDb();
  const tx = db.transaction(STORE, 'readwrite');
  tx.objectStore(STORE).clear();
  await txDone(tx);
  db.close();
}
